#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Edge {
	int L , R , lz , Min;
};
Edge tr[1000005];
pair < int , int > Cow[1000005];
int n , m , C[1000005];
int ans;
bool cmp( pair < int , int > a , pair < int , int > b ) {
	if( a.second != b.second ) {
		return a.second < b.second;
	}
	return a.first < b.first;
}
void build( int p , int L , int R ) {
	tr[p] = { L , R , 0 , ( int )1e9 };
	if( L == R ) {
		tr[p].Min = C[L];
		return;
	}
	int mid = ( L + R ) / 2;
	build( p << 1 , L , mid );
	build( p << 1 | 1 , mid + 1 , R );
	tr[p].Min = min( tr[p << 1].Min , tr[p << 1 | 1].Min );
}
void uplz( int p , int lz ) {
	tr[p].lz += lz;
	tr[p].Min -= lz;
}
void pushdown( int p ) {
	if( tr[p].lz ) {
		uplz( p << 1 , tr[p].lz );
		uplz( ( p << 1 ) + 1 , tr[p].lz );
		tr[p].lz = 0;
	}
}
void modify( int p , int l , int r ) {
	if( tr[p].L > r || tr[p].R < l ) {
		return;
	}
	if( tr[p].L >= l && tr[p].R <= r ) {
		uplz( p , 1 );
		return;
	}
	pushdown( p );
	modify( p << 1 , l , r );
	modify( ( p << 1 ) + 1 , l , r );
	tr[p].Min = min( tr[p << 1].Min , tr[( p << 1 ) + 1].Min );
}
int query( int p , int a , int b ) {
	if( tr[p].L > b || tr[p].R < a ) {
		return ( int )1e18;
	}
	if( tr[p].L >= a && tr[p].R <= b ) {
		return tr[p].Min;
	}
	int sum = 0;
	pushdown( p );
	sum = min( query( p << 1 , a , b ) , query( ( p << 1 ) + 1 , a , b ) );
	return sum;
}
signed main() {
	cin >> n >> m;
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> C[i];
	}
	build( 1 , 1 , n );
	for( int i = 1 ; i <= m ; i++ ) {
		cin >> Cow[i].first >> Cow[i].second;
	}
	sort( Cow + 1 , Cow + m + 1 , cmp );
	for( int i = 1 ; i <= m ; i++ ) {
		if( query( 1 , Cow[i].first , Cow[i].second ) > 0 ) {
			ans++;
			modify( 1 , Cow[i].first , Cow[i].second );
		}
	}
	cout << ans;
	return 0;
}
